// UNPATCHED SymCryptMlDsaRejBoundedPoly (sub_180096b4c) - key loop logic:
uint32_t edi = 0;                              // output index
do {
    SymCryptKeccakExtract(&sponge, &b, 1, 0);  // next SHAKE byte
    uint8_t al = *(uint8_t*)(params + 0x16);   // eta (constant 2 or 4)
    uint8_t dl = b & 0xf;                        // low nibble
    uint8_t r8;
    if (al == 2) { r8 = (dl >= 0xf) ? 0x80 : ((dl*0xd)>>6)*5 - dl + 2; }
    else if (al == 4 && dl < 9) { r8 = 4 - dl; }
    else { r8 = 0x80; }                          // reject
    // second nibble -> dl or 0x80
    if (r8 != 0x80) { out[edi] = ...; edi++; }   // advance only on accept
    if (dl != 0x80) { if (edi >= 0x100) break; out[edi] = ...; edi++; }
} while (edi < 0x100);                          // exit depends solely on edi advancing (CWE-835)

