// UNPATCHED SymCryptMlDsaRejNttPoly (sub_180096cec) - key loop logic:
// SymCryptKeccakAppend(&sponge, rho_i_j, 0x22);        // 0x180096D5C
uint32_t rbx = 0x100;                                    // 0x180096D69 output count = 256
do {
    SymCryptKeccakExtract(&sponge, &v, 3, 0);            // 0x180096D7F squeeze 3 bytes
    ((uint8_t*)&v)[2] &= 0x7f;                            // 0x180096D84 mask top bit -> 23-bit
    uint32_t eax = v;                                     // 0x180096D89
    if (eax >= 0x7FE001) continue;                        // 0x180096D92 reject (>= q), no counter
    *out++ = eax;                                         // 0x180096D94 store accepted
    rbx--;                                               // 0x180096D9A decrement ONLY on accept
} while (rbx != 0);                                       // 0x180096D9E only exit is 256 accepts (CWE-835)

